+      MaxTripCount <= UP.MaxUpperBound) {
+    LLVM_DEBUG(dbgs().indent(2)
+               << "Unrolling with max trip count: " << MaxTripCount << "\n");
     return MaxTripCount;
+  }

   return std::nullopt;
 }
